class Solution:
    def scoreDifference(self, nums) -> int:
        active = 0
        scores = [0, 0]
        for i, v in enumerate(nums):
            if v % 2 == 1:
                active ^= 1
            if i % 6 == 5:
                active ^= 1
            scores[active] += v
        return scores[0] - scores[1]

