var scoreDifference = function(nums) {
    let active = 0;
    const scores = [0, 0];
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (v % 2 === 1) active ^= 1;
        if (i % 6 === 5) active ^= 1;
        scores[active] += v;
    }
    return scores[0] - scores[1];
};
